#include<bits/stdc++.h>
using namespace std;
int c[2005][2005], dp[2005][2005];
int t, mod, n, m;
void init() {
	c[0][0] = 1;
	c[1][0] = 1;
	c[1][1] = 1;
	for (int i = 2; i <= 2000; i++) {
		c[i][0] = 1;
		for (int j = 1; j <= i; j++) {
			c[i][j] = (c[i - 1][j - 1] + c[i - 1][j]) % mod;
			dp[i][j] = dp[i - 1][j] + dp[i][j - 1] - dp[i - 1][j - 1];
			if (!c[i][j]) {
				dp[i][j]++;
			}
		}
		dp[i][i + 1] = dp[i][i];
	}
}
int main() {
	cin >> t >> mod;
	init();
	while (t--) {
		cin >> n >> m;
		if (m > n) cout << dp[n][n] << "\n";
		else cout << dp[n][m]  <<"\n";
	}
	return 0;
}
